mapper.select:
/* IvatCarryoverMapper.selectIvatCarryoverCount 당일 마감재고 여부 조회 */
SELECT COUNT(1)
  FROM TWORK_INFO_IVATXLCXULC_CARRYOVER
 WHERE CTKEY = #{ctkey}
   AND OWKEY = #{owkey}
   AND IVATSTANDARDDATE = TO_CHAR(CURRENT_TIMESTAMP,'YYYYMMDD')

mapper.delete:
/* IvatCarryoverMapper.deleteIvatCarryover 당일 마감재고 삭제 */
DELETE
  FROM TWORK_INFO_IVATXLCXULC_CARRYOVER
 WHERE CTKEY = #{ctkey}
   AND OWKEY = #{owkey}
   AND IVATSTANDARDDATE = TO_CHAR(CURRENT_TIMESTAMP,'YYYYMMDD')
